def estimate_limits(ctx):
    """Return one LimitEstimate per joint in ctx.joints."""
    import math

    initial_estimates = []
    for joint_name in sorted((getattr(ctx, "joints", {}) or {})):
        evidence = (getattr(ctx, "evidence", {}) or {}).get(joint_name, {}) or {}
        initial = evidence.get("initial_estimate")
        if initial is None:
            initial_estimates = []
            break
        initial_estimates.append(
            LimitEstimate(
                joint_name=joint_name,
                lower=float(initial["lower"]),
                upper=float(initial["upper"]),
                axis_world=[float(value) for value in initial["axis_world"]],
                confidence=0.25,
                reason=(
                    "State per joint: need_fix. Starting from rough VLM initial JSON; "
                    "agent must refine axis by <=5deg and limits by allowed mm/degree steps."
                ),
            )
        )
    if initial_estimates:
        return initial_estimates

    CARDINAL = {
        "+X": [1.0, 0.0, 0.0],
        "-X": [-1.0, 0.0, 0.0],
        "+Y": [0.0, 1.0, 0.0],
        "-Y": [0.0, -1.0, 0.0],
        "+Z": [0.0, 0.0, 1.0],
        "-Z": [0.0, 0.0, -1.0],
    }

    def _ev(joint_name):
        return (getattr(ctx, "evidence", {}) or {}).get(joint_name, {}) or {}

    def _labels(joint_name):
        return " ".join(str(x) for x in (_ev(joint_name).get("labels") or [])).lower()

    def _axis_label(axis):
        if not axis or len(axis) < 3:
            return None
        vals = [float(axis[0]), float(axis[1]), float(axis[2])]
        idx = max(range(3), key=lambda i: abs(vals[i]))
        return ("+" if vals[idx] >= 0.0 else "-") + "XYZ"[idx]

    def _snap_axis(axis):
        lab = _axis_label(axis)
        if lab in CARDINAL:
            return CARDINAL[lab][:], lab
        return None, None

    def _choose_axis(joint_name, joint):
        evidence = _ev(joint_name)
        candidates = evidence.get("axis_candidates") or []
        labels = _labels(joint_name)
        joint_type = joint.get("type")

        candidate_labels = set()
        for c in candidates:
            lab = c.get("axis_label")
            if lab not in CARDINAL:
                _, lab = _snap_axis(c.get("axis_world"))
            if lab in CARDINAL:
                candidate_labels.add(lab)

        rec = evidence.get("recommended_axis_label")
        if rec in CARDINAL and (not candidate_labels or rec in candidate_labels):
            return CARDINAL[rec][:], rec, "correct: kept/used recommended signed axis from evidence"

        if candidates:
            scored = []
            for idx, c in enumerate(candidates):
                lab = c.get("axis_label")
                if lab not in CARDINAL:
                    _, lab = _snap_axis(c.get("axis_world"))
                if lab not in CARDINAL:
                    continue

                try:
                    score = float(c.get("score", 0.0))
                except Exception:
                    score = 0.0

                reason = str(c.get("reason") or "")
                bonus = 0.0
                if joint_type == "prismatic" and any(k in labels for k in ("drawer", "tray", "basket", "pan", "bin")):
                    if "centroid-outward" in reason or "outward" in reason:
                        bonus += 0.25
                    if "authored" in reason:
                        bonus -= 0.05

                scored.append((score + bonus, -idx, lab, reason or "axis candidate"))

            if scored:
                scored.sort(reverse=True)
                _, _, lab, why = scored[0]
                return CARDINAL[lab][:], lab, "need_fix: changed/selected best evidence axis candidate (%s)" % why

        axis, lab = _snap_axis(joint.get("axis_world"))
        if axis is not None:
            return axis, lab, "correct: retained authored axis snapped to signed cardinal"

        return CARDINAL["+X"][:], "+X", "need_fix: missing axis, defaulted to +X signed cardinal"

    def _evidence_range(joint_name):
        evidence = _ev(joint_name)
        for key in ("limit", "limits", "range", "estimated_range", "action_range", "drawer_range"):
            val = evidence.get(key)
            if isinstance(val, dict):
                lo = val.get("lower", val.get("min"))
                hi = val.get("upper", val.get("max"))
                if lo is not None and hi is not None:
                    try:
                        return float(lo), float(hi), "correct: range taken from evidence field '%s'" % key
                    except Exception:
                        pass
            elif isinstance(val, (list, tuple)) and len(val) >= 2:
                try:
                    return float(val[0]), float(val[1]), "correct: range taken from evidence field '%s'" % key
                except Exception:
                    pass
        return None

    estimates = []

    for joint_name, joint in sorted((getattr(ctx, "joints", {}) or {}).items()):
        joint_type = joint.get("type")
        labels = _labels(joint_name)
        axis, lab, axis_reason = _choose_axis(joint_name, joint)
        ev_range = _evidence_range(joint_name)

        if joint_type == "revolute":
            if ev_range is not None:
                lower, upper, range_reason = ev_range
                confidence = 0.82
            elif "temperature" in labels or "temp" in labels:
                lower, upper = 0.0, 1.5 * math.pi
                range_reason = "correct: temperature knob uses a finite one-sided 270 degree sweep"
                confidence = 0.78
            elif "timer" in labels:
                lower, upper = 0.0, 1.5 * math.pi
                range_reason = "correct: timer knob uses a finite one-sided 270 degree sweep from off/rest"
                confidence = 0.78
            elif "knob" in labels or "dial" in labels:
                lower, upper = 0.0, 1.5 * math.pi
                range_reason = "correct: generic appliance knob uses a finite one-sided 270 degree sweep"
                confidence = 0.68
            else:
                lower, upper = -0.5 * math.pi, 0.5 * math.pi
                range_reason = "need_fix: no stronger cue, used conservative symmetric +/-90 degree range"
                confidence = 0.40

            estimates.append(
                LimitEstimate(
                    joint_name=joint_name,
                    lower=lower,
                    upper=upper,
                    axis_world=axis,
                    axis_label=lab,
                    confidence=confidence,
                    reason=(
                        "State per joint: correct unless future validation indicates otherwise. "
                        "Revolute estimate uses signed cardinal action axis %s (%s). %s. "
                        "No previous validation feedback was available, so no +/-0.001 bounded range correction was applied."
                    ) % (lab, axis_reason, range_reason),
                )
            )
            continue

        if joint_type == "prismatic":
            is_drawer = any(
                cue in labels
                for cue in (
                    "pull-out",
                    "pull out",
                    "drawer",
                    "pan",
                    "tray",
                    "basket",
                    "bin",
                    "fryer basket",
                    "air fryer",
                    "抽屉",
                    "炸篮",
                    "炸桶",
                )
            )

            if ev_range is not None:
                lower, upper, range_reason = ev_range
                confidence = 0.84 if is_drawer else 0.62
            elif is_drawer:
                lower, upper = 0.0, 0.16
                range_reason = (
                    "correct: closed pose is q=0 and compact appliance pull-out drawer/pan "
                    "travels about 16 cm along the outward signed axis"
                )
                confidence = 0.80
            else:
                lower, upper = 0.0, 0.10
                range_reason = "need_fix: no stronger cue, used modest positive 10 cm generic travel"
                confidence = 0.45

            estimates.append(
                LimitEstimate(
                    joint_name=joint_name,
                    lower=lower,
                    upper=upper,
                    axis_world=axis,
                    axis_label=lab,
                    confidence=confidence,
                    reason=(
                        "State per joint: correct unless future validation indicates otherwise. "
                        "Prismatic estimate uses signed cardinal translation axis %s (%s). %s. "
                        "No previous validation feedback was available, so no +/-0.001 bounded range correction was applied."
                    ) % (lab, axis_reason, range_reason),
                )
            )
            continue

        estimates.append(
            LimitEstimate(
                joint_name=joint_name,
                lower=0.0,
                upper=0.0,
                axis_world=axis,
                axis_label=lab,
                confidence=0.20,
                reason=(
                    "State per joint: need_fix because joint type is unsupported or missing. "
                    "Returned a zero-motion estimate on signed cardinal action axis %s (%s)."
                ) % (lab, axis_reason),
            )
        )

    return estimates

def estimate_limits(ctx):
    """Return one bounded-action LimitEstimate per joint in ctx.joints."""
    import math

    evidence_all = getattr(ctx, "evidence", {}) or {}
    feedback = str(getattr(ctx, "last_feedback", "") or evidence_all.get("__last_feedback__", "") or "")

    DEG5 = math.radians(5.0)
    REV_STEP = math.radians(10.0)  # allowed ladder: 10 deg
    PRI_STEP = 0.010               # allowed ladder: 10 mm

    def _initial(joint_name, joint):
        ev = evidence_all.get(joint_name, {}) or {}
        init = ev.get("initial_estimate") or {}
        axis = init.get("axis_world", joint.get("axis_world", [1.0, 0.0, 0.0]))
        lower = init.get("lower", 0.0)
        upper = init.get("upper", 0.0)
        return [float(axis[0]), float(axis[1]), float(axis[2])], float(lower), float(upper)

    def _norm(v):
        n = math.sqrt(sum(float(x) * float(x) for x in v))
        if n <= 1e-12:
            return [1.0, 0.0, 0.0]
        return [float(x) / n for x in v]

    def _target_axis(joint_name, joint):
        ev = evidence_all.get(joint_name, {}) or {}
        rec = ev.get("recommended_axis_world")
        if rec and len(rec) >= 3:
            return _norm(rec)

        cands = ev.get("axis_candidates") or []
        if cands:
            best = None
            best_score = -1e100
            labels = " ".join(str(x).lower() for x in (ev.get("labels") or []))
            for c in cands:
                aw = c.get("axis_world")
                if not aw or len(aw) < 3:
                    continue
                score = float(c.get("score", 0.0) or 0.0)
                reason = str(c.get("reason") or "").lower()
                if joint.get("type") == "prismatic" and any(k in labels for k in ("drawer", "pan", "tray", "basket")):
                    if "outward" in reason:
                        score += 0.25
                    if "authored" in reason:
                        score -= 0.05
                if score > best_score:
                    best_score = score
                    best = aw
            if best is not None:
                return _norm(best)

        return _norm(joint.get("axis_world", [1.0, 0.0, 0.0]))

    def _rotate_toward(cur, tgt, max_angle):
        cur = _norm(cur)
        tgt = _norm(tgt)
        dot = max(-1.0, min(1.0, sum(cur[i] * tgt[i] for i in range(3))))
        ang = math.acos(dot)
        if ang <= 1e-12:
            return cur
        if ang <= max_angle:
            return tgt
        t = max_angle / ang
        s0 = math.sin((1.0 - t) * ang) / math.sin(ang)
        s1 = math.sin(t * ang) / math.sin(ang)
        return _norm([s0 * cur[i] + s1 * tgt[i] for i in range(3)])

    estimates = []

    for joint_name, joint in sorted((getattr(ctx, "joints", {}) or {}).items()):
        ev = evidence_all.get(joint_name, {}) or {}
        labels = " ".join(str(x).lower() for x in (ev.get("labels") or []))
        joint_type = joint.get("type")

        axis0, lower0, upper0 = _initial(joint_name, joint)
        target = _target_axis(joint_name, joint)
        axis = _rotate_toward(axis0, target, DEG5)

        lower = lower0
        upper = upper0
        state = "need_fix"
        range_reason = "stayed unchanged this iteration"

        if joint_type == "revolute":
            if joint_name in feedback and "invalid at q=-" in feedback:
                lower = lower0 + REV_STEP
                upper = upper0
                range_reason = (
                    "need_fix: previous validation reported invalid negative motion; "
                    "bounded action raised lower by +10 degrees"
                )
            elif "temperature" in labels or "temp" in labels:
                lower = lower0
                upper = upper0 + REV_STEP
                range_reason = (
                    "need_fix: temperature knob should have positive finite sweep; "
                    "bounded action increased upper by +10 degrees"
                )
            elif "timer" in labels:
                lower = lower0 + REV_STEP if lower0 < 0.0 else lower0
                upper = upper0
                range_reason = (
                    "need_fix: timer knob should not require large negative sweep; "
                    "bounded action raised lower by +10 degrees"
                )
            elif "knob" in labels or "dial" in labels:
                upper = upper0 + REV_STEP
                range_reason = (
                    "need_fix: generic knob range expanded by one allowed +10 degree step"
                )

            estimates.append(
                LimitEstimate(
                    joint_name=joint_name,
                    lower=lower,
                    upper=upper,
                    axis_world=axis,
                    confidence=0.42,
                    reason=(
                        "State per joint: %s. Previous/current axis was %s; evidence target is %s, "
                        "so this iteration rotates the current unit axis toward the target by no more "
                        "than 5 degrees. Revolute limits changed by at most one allowed 10 degree "
                        "step. %s."
                    ) % (state, axis0, target, range_reason),
                )
            )
            continue

        if joint_type == "prismatic":
            is_drawer = any(k in labels for k in ("pull-out", "pull out", "drawer", "pan", "tray", "basket", "bin"))
            if is_drawer:
                lower = lower0
                upper = upper0 + PRI_STEP
                range_reason = (
                    "need_fix: pull-out drawer/pan visual cue suggests longer travel; "
                    "bounded action increased upper by +10 mm"
                )

            estimates.append(
                LimitEstimate(
                    joint_name=joint_name,
                    lower=lower,
                    upper=upper,
                    axis_world=axis,
                    confidence=0.45,
                    reason=(
                        "State per joint: %s. Previous/current axis was %s; evidence target is %s, "
                        "so this iteration rotates the current unit axis toward the target by no more "
                        "than 5 degrees. Prismatic limits changed by at most one allowed 10 mm step. "
                        "%s."
                    ) % (state, axis0, target, range_reason),
                )
            )
            continue

        estimates.append(
            LimitEstimate(
                joint_name=joint_name,
                lower=lower,
                upper=upper,
                axis_world=axis,
                confidence=0.20,
                reason=(
                    "State per joint: need_fix. Unsupported joint type; kept limits unchanged and "
                    "only applied the bounded <=5 degree axis action toward evidence target."
                ),
            )
        )

    return estimates

